
-- SG SecureBank - 50 clients de test


DROP TABLE fraud CASCADE CONSTRAINTS;
DROP TABLE transactions CASCADE CONSTRAINTS;
DROP TABLE comptes CASCADE CONSTRAINTS;
DROP TABLE clients CASCADE CONSTRAINTS;

CREATE TABLE clients (
    client_id       NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    nom             VARCHAR2(100)   NOT NULL,
    prenom          VARCHAR2(100)   NOT NULL,
    email           VARCHAR2(150)   UNIQUE NOT NULL,
    mot_de_passe    VARCHAR2(255)   NOT NULL,
    telephone       VARCHAR2(20),
    date_naissance  DATE            NOT NULL,
    adresse         VARCHAR2(255),
    pays            VARCHAR2(100)   DEFAULT 'France',
    date_creation   TIMESTAMP       DEFAULT CURRENT_TIMESTAMP,
    statut          VARCHAR2(20)    DEFAULT 'ACTIF'
                    CHECK (statut IN ('ACTIF', 'SUSPENDU', 'CLOTURE'))
);

CREATE TABLE comptes (
    compte_id       NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    client_id       NUMBER          NOT NULL,
    numero_compte   VARCHAR2(34)    UNIQUE NOT NULL,
    type_compte     VARCHAR2(20)    NOT NULL
                    CHECK (type_compte IN ('COURANT', 'EPARGNE', 'PROFESSIONNEL')),
    solde           NUMBER(15, 2)   DEFAULT 0.00,
    devise          VARCHAR2(10)    DEFAULT 'EUR',
    date_ouverture  DATE            DEFAULT SYSDATE,
    statut          VARCHAR2(20)    DEFAULT 'ACTIF'
                    CHECK (statut IN ('ACTIF', 'BLOQUE', 'CLOTURE')),
    CONSTRAINT fk_compte_client FOREIGN KEY (client_id) REFERENCES clients(client_id)
);

CREATE TABLE transactions (
    transaction_id      NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    compte_id           NUMBER          NOT NULL,
    type_transaction    VARCHAR2(30)    NOT NULL
                        CHECK (type_transaction IN ('PAIEMENT_EN_LIGNE','VIREMENT','RETRAIT','DEPOT','TRANSACTION_MOBILE')),
    montant             NUMBER(15, 2)   NOT NULL,
    devise              VARCHAR2(10)    DEFAULT 'EUR',
    pays_origine        VARCHAR2(100),
    pays_destination    VARCHAR2(100),
    date_transaction    TIMESTAMP       DEFAULT CURRENT_TIMESTAMP,
    ip_adresse          VARCHAR2(50),
    statut              VARCHAR2(20)    DEFAULT 'EN_ATTENTE'
                        CHECK (statut IN ('EN_ATTENTE','VALIDEE','REJETEE','EN_ANALYSE')),
    score_risque        NUMBER(5, 2)    DEFAULT 0.00,
    CONSTRAINT fk_transaction_compte FOREIGN KEY (compte_id) REFERENCES comptes(compte_id)
);

CREATE TABLE fraud (
    fraud_id            NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    transaction_id      NUMBER          NOT NULL,
    type_fraude         VARCHAR2(50)
                        CHECK (type_fraude IN ('PHISHING','USURPATION_IDENTITE','TRANSACTION_INHABITUELLE','ACCES_NON_AUTORISE','AUTRE')),
    niveau_risque       VARCHAR2(20)    DEFAULT 'MOYEN'
                        CHECK (niveau_risque IN ('FAIBLE','MOYEN','ELEVE','CRITIQUE')),
    score_ml            NUMBER(5, 2),
    date_detection      TIMESTAMP       DEFAULT CURRENT_TIMESTAMP,
    statut_analyse      VARCHAR2(20)    DEFAULT 'EN_COURS'
                        CHECK (statut_analyse IN ('EN_COURS','CONFIRME','FAUX_POSITIF','RESOLU')),
    analyste_id         VARCHAR2(50),
    commentaire         VARCHAR2(500),
    CONSTRAINT fk_fraud_transaction FOREIGN KEY (transaction_id) REFERENCES transactions(transaction_id)
);

CREATE INDEX idx_transactions_compte ON transactions(compte_id);
CREATE INDEX idx_transactions_date   ON transactions(date_transaction);
CREATE INDEX idx_transactions_statut ON transactions(statut);
CREATE INDEX idx_fraud_transaction   ON fraud(transaction_id);
CREATE INDEX idx_fraud_niveau        ON fraud(niveau_risque);
CREATE INDEX idx_comptes_client      ON comptes(client_id);

